     4→import { marked } from 'marked';
     5→import type { Env, Update } from '@/types';
     6→import { escapeHtml } from '@/utils';
     7→
     8→/**
     9→ * Handles GET requests to /updates/{slug}
    10→ * Fetches update JSON from static assets, checks visibility, and renders the page
    11→ */
    12→export async function handleUpdatePage(request: Request, env: Env, slug: string): Promise<Response> {
    13→  try {
    14→    // Fetch the update JSON via the ASSETS binding to avoid self-referential Worker routing
    15→    const url = new URL(request.url);
    16→    const updateUrl = `${url.origin}/updates/data/${slug}.json`;
    17→    const updateResponse = await (env.ASSETS?.fetch(new Request(updateUrl)) ?? fetch(updateUrl));
    18→
    19→    if (!updateResponse.ok) {
    20→      return fetchNotFoundPage(request, env);
    21→    }
    22→
    23→    const update: Update = await updateResponse.json();
    24→
    25→    // Return 404 for draft updates (public users shouldn't see them)
    26→    if (update.status === 'draft') {
    27→      return fetchNotFoundPage(request, env);
    28→    }
    29→
    30→    return renderUpdatePage(update);
    31→  } catch (error) {
    32→    console.error('Error handling update page:', error);
    33→    return new Response('Error loading update', { status: 500 });
    34→  }
    35→}
    36→
    37→/**
    38→ * Fetches and returns the site's 404 page from static assets with a 404 status code.
    39→ */
    40→async function fetchNotFoundPage(request: Request, env: Env): Promise<Response> {
    41→  const url = new URL(request.url);
    42→  const notFoundUrl = `${url.origin}/errors/not_found.html`;
    43→  const response = await (env.ASSETS?.fetch(new Request(notFoundUrl)) ?? fetch(notFoundUrl));
    44→  const html = await response.text();
    45→  return new Response(html, {
    46→    status: 404,
    47→    headers: { 'Content-Type': 'text/html; charset=utf-8' },
    48→  });
    49→}
    50→
    51→/**
    52→ * Renders an Update object to a full HTML Response.
    53→ * Used by both the public route and the admin preview route.
    54→ */
    55→export async function renderUpdatePage(update: Update): Promise<Response> {
    56→  // Convert markdown to HTML
    57→  const contentHTML = await marked(update.content);
    58→
    59→  // Sanitize HTML to prevent XSS
    60→  const sanitizedHTML = sanitizeHTML(contentHTML);
    61→
    62→  // Render the page
    63→  const html = renderUpdatePageHTML(update, sanitizedHTML);
    64→
    65→  return new Response(html, {
    66→    status: 200,
    67→    headers: {
    68→      'Content-Type': 'text/html; charset=utf-8',
    69→      'Content-Security-Policy': "default-src 'self'; script-src 'self' https://www.googletagmanager.com https://static.cloudflareinsights.com; style-src 'self' 'unsafe-inline'; img-src 'self'; connect-src 'self' https://www.google-analytics.com https://cloudflareinsights.com; frame-ancestors 'none'; base-uri 'self';",
    70→    },
    71→  });
    72→}
    73→
    74→/**
    75→ * Renders the individual update page HTML
    76→ */
    77→function renderUpdatePageHTML(update: Update, contentHTML: string): string {
    78→  const publishedDate = new Date(update.publishedDate);
    79→  const formattedPublishedDate = publishedDate.toLocaleDateString('en-GB', {
    80→    year: 'numeric',
    81→    month: 'long',
    82→    day: 'numeric',
    83→  });
    84→
    85→  const editedDate = new Date(update.editedDate);
    86→  const showEditedDate = update.editedDate !== update.publishedDate;
    87→  const formattedEditedDate = editedDate.toLocaleDateString('en-GB', {
    88→    year: 'numeric',
    89→    month: 'long',
    90→    day: 'numeric',
    91→  });
    92→
    93→  const editedDateHTML = showEditedDate
    94→    ? `<p style="color: #666; font-size: 0.9em; font-style: italic;">Last edited: ${formattedEditedDate}</p>`
    95→    : '';
    96→
    97→  const ogImage = update.images.length > 0
    98→    ? `https://hultberg.org${update.images[0]}`
    99→    : 'https://hultberg.org/now/magnus_hultberg_juggling.png';
   100→
   101→  const ogDescription = escapeHtml(update.excerpt || update.title);
   102→
   103→  return `<!doctype html>
   104→<html class="no-js" lang="en-GB">
   105→    <head>
   106→        <meta charset="utf-8" />
   107→        <meta http-equiv="X-UA-Compatible" content="IE=edge" />
   108→        <title>${escapeHtml(update.title)} - Magnus Hultberg</title>
   109→        <meta name="description" content="${ogDescription}" />
   110→        <meta name="author" content="${escapeHtml(update.author)}" />
   111→        <meta name="viewport" content="width=device-width, initial-scale=1" />
   112→
   113→        <meta property="og:title" content="${escapeHtml(update.title)}" />
   114→        <meta property="og:type" content="article" />
   115→        <meta property="og:url" content="https://hultberg.org/updates/${escapeHtml(update.slug)}" />
   116→        <meta property="og:image" content="${ogImage}" />
   117→        <meta property="og:description" content="${ogDescription}" />
   118→        <meta property="og:site_name" content="Magnus Hultberg" />
   119→        <meta property="article:author" content="Magnus Hultberg" />
   120→        <meta property="article:published_time" content="${escapeHtml(update.publishedDate)}" />
   121→        <meta name="twitter:card" content="${update.images.length > 0 ? 'summary_large_image' : 'summary'}" />
   122→
   123→        <link rel="alternate" type="application/rss+xml" title="Updates - Magnus Hultberg" href="/updates/feed.xml" />
   124→
