   143→                        By <a href="/now">${escapeHtml(update.author)}</a> • ${formattedPublishedDate}
   144→                    </p>
   145→                    ${editedDateHTML}
   146→                </header>
   147→
   148→                <div>
   149→                    ${contentHTML}
   150→                </div>
   151→            </article>
   152→
   153→            <p>← <a href="/">Home</a> | <a href="/updates">Updates</a> | <a href="https://www.linkedin.com/in/hultberg/">LinkedIn</a></p>
   154→        </div>
   155→    </body>
   156→</html>
   157→`;
   158→}
   159→
   160→/**
   161→ * Sanitize HTML to prevent XSS attacks
   162→ *
   163→ * TODO: Replace with proper allowlist-based sanitizer when Workers-compatible library available
   164→ * Current approach uses regex-based filtering which is not ideal but acceptable for MVP because:
   165→ * - Single trusted admin (no untrusted user input)
   166→ * - Content version-controlled in GitHub
   167→ * - CSP headers provide defense-in-depth
   168→ * - Server-side rendering only
   169→ *
   170→ * See CLAUDE.md Technical Debt section for details
   171→ */
   172→function sanitizeHTML(html: string): string {
   173→  let sanitized = html;
   174→
   175→  // Preserve img tags but sanitize them individually (remove event handlers, keep width/height/style)
   176→  const imgTags: string[] = [];
   177→  const imgPlaceholder = '___IMG_PLACEHOLDER_';
   178→  sanitized = sanitized.replace(/<img\b[^>]*>/gi, (match) => {
   179→    // Remove event handlers from img tag
   180→    let cleanImg = match
   181→      .replace(/on\w+\s*=\s*["'][^"']*["']/gi, '')
   182→      .replace(/on\w+\s*=\s*[^\s>]*/gi, '')
   183→      .replace(/\son\w+=/gi, '');
   184→    imgTags.push(cleanImg);
   185→    return `${imgPlaceholder}${imgTags.length - 1}___`;
   186→  });
   187→
   188→  // Remove dangerous tags completely
   189→  sanitized = sanitized
   190→    .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '')
   191→    .replace(/<iframe\b[^<]*(?:(?!<\/iframe>)<[^<]*)*<\/iframe>/gi, '')
   192→    .replace(/<object\b[^<]*(?:(?!<\/object>)<[^<]*)*<\/object>/gi, '')
   193→    .replace(/<embed\b[^>]*>/gi, '')
   194→    .replace(/<applet\b[^<]*(?:(?!<\/applet>)<[^<]*)*<\/applet>/gi, '')
   195→    .replace(/<base\b[^>]*>/gi, '')
   196→    .replace(/<link\b[^>]*>/gi, '')
   197→    .replace(/<meta\b[^>]*>/gi, '')
   198→    .replace(/<form\b[^<]*(?:(?!<\/form>)<[^<]*)*<\/form>/gi, '');
   199→
