// ABOUT: Route handler for /updates/{slug} individual update pages
// ABOUT: Renders markdown content with metadata and sanitizes HTML

import { marked } from 'marked';
import type { Env, Update } from '@/types';
import { escapeHtml } from '@/utils';

/**
 * Handles GET requests to /updates/{slug}
 * Fetches update JSON from static assets, checks visibility, and renders the page
 */
export async function handleUpdatePage(request: Request, env: Env, slug: string): Promise<Response> {
  try {
    // Fetch the update JSON via the ASSETS binding to avoid self-referential Worker routing
    const url = new URL(request.url);
    const updateUrl = `${url.origin}/updates/data/${slug}.json`;
    const updateResponse = await (env.ASSETS?.fetch(new Request(updateUrl)) ?? fetch(updateUrl));

    if (!updateResponse.ok) {
      return fetchNotFoundPage(request, env);
    }

    const update: Update = await updateResponse.json();

    // Return 404 for draft updates (public users shouldn't see them)
    if (update.status === 'draft') {
      return fetchNotFoundPage(request, env);
    }

    return renderUpdatePage(update);
  } catch (error) {
    console.error('Error handling update page:', error);
    return new Response('Error loading update', { status: 500 });
  }
}

/**
 * Fetches and returns the site's 404 page from static assets with a 404 status code.
 */
async function fetchNotFoundPage(request: Request, env: Env): Promise<Response> {
  const url = new URL(request.url);
  const notFoundUrl = `${url.origin}/errors/not_found.html`;
  const response = await (env.ASSETS?.fetch(new Request(notFoundUrl)) ?? fetch(notFoundUrl));
  const html = await response.text();
  return new Response(html, {
    status: 404,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });
}

/**
 * Renders an Update object to a full HTML Response.
 * Used by both the public route and the admin preview route.
 */
export async function renderUpdatePage(update: Update): Promise<Response> {
  // Convert markdown to HTML
  const contentHTML = await marked(update.content);

  // Sanitize HTML to prevent XSS
  const sanitizedHTML = sanitizeHTML(contentHTML);

  // Render the page
  const html = renderUpdatePageHTML(update, sanitizedHTML);

  return new Response(html, {
    status: 200,
    headers: {
      'Content-Type': 'text/html; charset=utf-8',
      'Content-Security-Policy': "default-src 'self'; script-src 'self' https://www.googletagmanager.com https://static.cloudflareinsights.com; style-src 'self' 'unsafe-inline'; img-src 'self'; connect-src 'self' https://www.google-analytics.com https://cloudflareinsights.com; frame-ancestors 'none'; base-uri 'self';",
    },
  });
}

/**
 * Renders the individual update page HTML
 */
function renderUpdatePageHTML(update: Update, contentHTML: string): string {
  const publishedDate = new Date(update.publishedDate);
  const formattedPublishedDate = publishedDate.toLocaleDateString('en-GB', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

  const editedDate = new Date(update.editedDate);
  const showEditedDate = update.editedDate !== update.publishedDate;
  const formattedEditedDate = editedDate.toLocaleDateString('en-GB', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

  const editedDateHTML = showEditedDate
    ? `<p style="color: #666; font-size: 0.9em; font-style: italic;">Last edited: ${formattedEditedDate}</p>`
    : '';

  const ogImage = update.images.length > 0
    ? `https://hultberg.org${update.images[0]}`
    : 'https://hultberg.org/now/magnus_hultberg_juggling.png';

  const ogDescription = escapeHtml(update.excerpt || update.title);

  return `<!doctype html>
<html class="no-js" lang="en-GB">
    <head>
        <meta charset="utf-8" />
        <meta http-equiv="X-UA-Compatible" content="IE=edge" />
        <title>${escapeHtml(update.title)} - Magnus Hultberg</title>
        <meta name="description" content="${ogDescription}" />
        <meta name="author" content="${escapeHtml(update.author)}" />
        <meta name="viewport" content="width=device-width, initial-scale=1" />

        <meta property="og:title" content="${escapeHtml(update.title)}" />
        <meta property="og:type" content="article" />
        <meta property="og:url" content="https://hultberg.org/updates/${escapeHtml(update.slug)}" />
        <meta property="og:image" content="${ogImage}" />
        <meta property="og:description" content="${ogDescription}" />
        <meta property="og:site_name" content="Magnus Hultberg" />
        <meta property="article:author" content="Magnus Hultberg" />
        <meta property="article:published_time" content="${escapeHtml(update.publishedDate)}" />
        <meta name="twitter:card" content="${update.images.length > 0 ? 'summary_large_image' : 'summary'}" />

        <link rel="alternate" type="application/rss+xml" title="Updates - Magnus Hultberg" href="/updates/feed.xml" />

        <script async src="https://www.googletagmanager.com/gtag/js?id=G-D1L22CCJTJ"></script>
        <script>
            window.dataLayer = window.dataLayer || [];
            function gtag(){dataLayer.push(arguments);}
            gtag('js', new Date());
            gtag('config', 'G-D1L22CCJTJ');
        </script>

        <!-- Cloudflare Web Analytics --><script defer src='https://static.cloudflareinsights.com/beacon.min.js' data-cf-beacon='{"token": "REDACTED"}'></script><!-- End Cloudflare Web Analytics -->
    </head>
    <body>
        <div style="max-width: 800px; margin: 0 auto; padding: 2em;">
            <p>← <a href="/">Home</a> | <a href="/updates">Updates</a> | <a href="https://www.linkedin.com/in/hultberg/">LinkedIn</a></p>

            <article>
                <header>
                    <h1>${escapeHtml(update.title)}</h1>
                    <p style="color: #666; font-size: 0.9em;">
                        By <a href="/now">${escapeHtml(update.author)}</a> • ${formattedPublishedDate}
                    </p>
                    ${editedDateHTML}
                </header>

                <div>
                    ${contentHTML}
                </div>
            </article>

            <p>← <a href="/">Home</a> | <a href="/updates">Updates</a> | <a href="https://www.linkedin.com/in/hultberg/">LinkedIn</a></p>
        </div>
    </body>
</html>
`;
}

/**
 * Sanitize HTML to prevent XSS attacks
 *
 * TODO: Replace with proper allowlist-based sanitizer when Workers-compatible library available
 * Current approach uses regex-based filtering which is not ideal but acceptable for MVP because:
 * - Single trusted admin (no untrusted user input)
 * - Content version-controlled in GitHub
 * - CSP headers provide defense-in-depth
 * - Server-side rendering only
 *
 * See CLAUDE.md Technical Debt section for details
 */
function sanitizeHTML(html: string): string {
  let sanitized = html;

  // Preserve img tags but sanitize them individually (remove event handlers, keep width/height/style)
  const imgTags: string[] = [];
  const imgPlaceholder = '___IMG_PLACEHOLDER_';
  sanitized = sanitized.replace(/<img\b[^>]*>/gi, (match) => {
    // Remove event handlers from img tag
    let cleanImg = match
      .replace(/on\w+\s*=\s*["'][^"']*["']/gi, '')
      .replace(/on\w+\s*=\s*[^\s>]*/gi, '')
      .replace(/\son\w+=/gi, '');
    imgTags.push(cleanImg);
    return `${imgPlaceholder}${imgTags.length - 1}___`;
  });

  // Remove dangerous tags completely
  sanitized = sanitized
    .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '')
    .replace(/<iframe\b[^<]*(?:(?!<\/iframe>)<[^<]*)*<\/iframe>/gi, '')
    .replace(/<object\b[^<]*(?:(?!<\/object>)<[^<]*)*<\/object>/gi, '')
    .replace(/<embed\b[^>]*>/gi, '')
    .replace(/<applet\b[^<]*(?:(?!<\/applet>)<[^<]*)*<\/applet>/gi, '')
    .replace(/<base\b[^>]*>/gi, '')
    .replace(/<link\b[^>]*>/gi, '')
    .replace(/<meta\b[^>]*>/gi, '')
    .replace(/<form\b[^<]*(?:(?!<\/form>)<[^<]*)*<\/form>/gi, '');

  // Remove dangerous protocols (case-insensitive, handle URL encoding)
  sanitized = sanitized
    .replace(/javascript:/gi, '')
    .replace(/data:/gi, '')
    .replace(/vbscript:/gi, '')
    .replace(/vbscript:/gi, '')
    .replace(/file:/gi, '')
    .replace(/about:/gi, '');

  // Remove inline event handlers (all variations)
  sanitized = sanitized
    .replace(/on\w+\s*=\s*["'][^"']*["']/gi, '')
    .replace(/on\w+\s*=\s*[^\s>]*/gi, '')
    .replace(/\son\w+=/gi, '');

  // Remove style attributes that could contain expressions (but NOT on img tags, which were extracted)
  sanitized = sanitized
    .replace(/style\s*=\s*["'][^"']*["']/gi, '')
    .replace(/style\s*=\s*[^\s>]*/gi, '');

  // Restore img tags with their preserved attributes (style, width, height allowed on images)
  sanitized = sanitized.replace(/___IMG_PLACEHOLDER_(\d+)___/g, (match, index) => {
    return imgTags[parseInt(index)];
  });

  return sanitized;
}

