      return fetchNotFoundPage(request, env);
    }

    return renderUpdatePage(update);
  } catch (error) {
    console.error('Error handling update page:', error);
    return new Response('Error loading update', { status: 500 });
  }
}

/**
 * Fetches and returns the site's 404 page from static assets with a 404 status code.
 */
async function fetchNotFoundPage(request: Request, env: Env): Promise<Response> {
  const url = new URL(request.url);
  const notFoundUrl = `${url.origin}/errors/not_found.html`;
  const response = await (env.ASSETS?.fetch(new Request(notFoundUrl)) ?? fetch(notFoundUrl));
  const html = await response.text();
  return new Response(html, {
    status: 404,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });
}

/**
 * Renders an Update object to a full HTML Response.
 * Used by both the public route and the admin preview route.
 */
export async function renderUpdatePage(update: Update): Promise<Response> {
  // Convert markdown to HTML
  const contentHTML = await marked(update.content);

  // Sanitize HTML to prevent XSS
  const sanitizedHTML = sanitizeHTML(contentHTML);

  // Render the page
  const html = renderUpdatePageHTML(update, sanitizedHTML);

  return new Response(html, {
    status: 200,
    headers: {
      'Content-Type': 'text/html; charset=utf-8',
      'Content-Security-Policy': "default-src 'self'; script-src 'self' https://www.googletagmanager.com https://static.cloudflareinsights.com; style-src 'self' 'unsafe-inline'; img-src 'self'; connect-src 'self' https://www.google-analytics.com https://cloudflareinsights.com; frame-ancestors 'none'; base-uri 'self';",
    },
  });
}

