/**
 * Sanitize HTML to prevent XSS attacks
 *
 * TODO: Replace with proper allowlist-based sanitizer when Workers-compatible library available
 * Current approach uses regex-based filtering which is not ideal but acceptable for MVP because:
 * - Single trusted admin (no untrusted user input)
 * - Content version-controlled in GitHub
 * - CSP headers provide defense-in-depth
 * - Server-side rendering only
 *
 * See CLAUDE.md Technical Debt section for details
 */
function sanitizeHTML(html: string): string {
  let sanitized = html;

  // Preserve img tags but sanitize them individually (remove event handlers, keep width/height/style)
  const imgTags: string[] = [];
  const imgPlaceholder = '___IMG_PLACEHOLDER_';
  sanitized = sanitized.replace(/<img\b[^>]*>/gi, (match) => {
    // Remove event handlers from img tag
    let cleanImg = match
      .replace(/on\w+\s*=\s*["'][^"']*["']/gi, '')
      .replace(/on\w+\s*=\s*[^\s>]*/gi, '')
      .replace(/\son\w+=/gi, '');
    imgTags.push(cleanImg);
    return `${imgPlaceholder}${imgTags.length - 1}___`;
  });

  // Remove dangerous tags completely
  sanitized = sanitized
    .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '')
    .replace(/<iframe\b[^<]*(?:(?!<\/iframe>)<[^<]*)*<\/iframe>/gi, '')
    .replace(/<object\b[^<]*(?:(?!<\/object>)<[^<]*)*<\/object>/gi, '')
    .replace(/<embed\b[^>]*>/gi, '')
    .replace(/<applet\b[^<]*(?:(?!<\/applet>)<[^<]*)*<\/applet>/gi, '')
    .replace(/<base\b[^>]*>/gi, '')
    .replace(/<link\b[^>]*>/gi, '')
    .replace(/<meta\b[^>]*>/gi, '')
    .replace(/<form\b[^<]*(?:(?!<\/form>)<[^<]*)*<\/form>/gi, '');

  // Remove dangerous protocols (case-insensitive, handle URL encoding)
  sanitized = sanitized
    .replace(/javascript:/gi, '')
    .replace(/data:/gi, '')
    .replace(/vbscript:/gi, '')
    .replace(/vbscript:/gi, '')
    .replace(/file:/gi, '')
    .replace(/about:/gi, '');

  // Remove inline event handlers (all variations)
  sanitized = sanitized
    .replace(/on\w+\s*=\s*["'][^"']*["']/gi, '')
    .replace(/on\w+\s*=\s*[^\s>]*/gi, '')
    .replace(/\son\w+=/gi, '');

  // Remove style attributes that could contain expressions (but NOT on img tags, which were extracted)
  sanitized = sanitized
    .replace(/style\s*=\s*["'][^"']*["']/gi, '')
    .replace(/style\s*=\s*[^\s>]*/gi, '');

  // Restore img tags with their preserved attributes (style, width, height allowed on images)
  sanitized = sanitized.replace(/___IMG_PLACEHOLDER_(\d+)___/g, (match, index) => {
    return imgTags[parseInt(index)];
  });

  return sanitized;
}

// ABOUT: Route handler for /updates listing page
// ABOUT: Displays published updates in reverse chronological order

import type { Env, UpdateIndex } from '@/types';
import { escapeHtml } from '@/utils';

/**
 * Handles GET requests to /updates
 * Fetches index.json, filters published updates, and renders HTML
 */
export async function handleUpdatesListing(request: Request, env: Env): Promise<Response> {
  try {
    // Fetch the index.json via the ASSETS binding to avoid self-referential Worker routing
    const url = new URL(request.url);
    const indexUrl = `${url.origin}/updates/data/index.json`;
    const indexResponse = await (env.ASSETS?.fetch(new Request(indexUrl)) ?? fetch(indexUrl));

    if (!indexResponse.ok) {
      throw new Error('Failed to fetch updates index');
    }

    const indexData: UpdateIndex = await indexResponse.json();

    // Filter for published updates only and sort by date (newest first)
    const publishedUpdates = indexData.updates
      .filter(update => update.status === 'published')
      .sort((a, b) => {
        return new Date(b.publishedDate).getTime() - new Date(a.publishedDate).getTime();
      });

    // Render HTML
    const html = renderUpdatesListingHTML(publishedUpdates);

    return new Response(html, {
      status: 200,
      headers: {
        'Content-Type': 'text/html; charset=utf-8',
        'Content-Security-Policy': "default-src 'self'; script-src 'self' https://www.googletagmanager.com https://static.cloudflareinsights.com; style-src 'self' 'unsafe-inline'; img-src 'self'; connect-src 'self' https://www.google-analytics.com https://cloudflareinsights.com; frame-ancestors 'none'; base-uri 'self';",
      },
    });
  } catch (error) {
    console.error('Error handling updates listing:', error);
    return new Response('Error loading updates', { status: 500 });
  }
}

